import{_ as t,o,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"55. Personal Leave","description":"","frontmatter":{"title":"55. Personal Leave","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","personal-leave","hours","overtime"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/leave/55-personal-leave.md","filePath":"ebas/has-managers-admin/common-terms/leave/55-personal-leave.md"}'),n={name:"ebas/has-managers-admin/common-terms/leave/55-personal-leave.md"};function s(i,e,l,p,h,c){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_55-personal-leave" tabindex="-1">55. Personal Leave <a class="header-anchor" href="#_55-personal-leave" aria-label="Permalink to &quot;55. Personal Leave&quot;">​</a></h1><p>This clause does not apply to casual Employees. The entitlements of casual Employees are set out in <a href="/eba/ebas/has-managers-admin/common-terms/employment-types/23-casual-employment.html">clause 23</a> (Casual Employment).</p><p><strong>55.1</strong> Amount of Paid Personal Leave</p><p><strong>(a)</strong> Paid personal leave accrues progressively during a year of service according to the Employee&#39;s ordinary hours of work (excluding overtime) and accumulates from year to year.</p><p><strong>(b)</strong> An Employee other than Dental Assistants employed by DHSV or Ballarat Health Service is entitled to the following amount of paid personal leave:</p><p><strong>(i)</strong> 91 hours and 12 minutes or as provided by the NES (whichever is greater) in the first year of service;</p><p><strong>(ii)</strong> 106 hours and 24 minutes or as provided by the NES (whichever is the greater) in each year in the second, third and fourth years of service;</p><p><strong>(iii)</strong> 159.6 hours in the fifth and following years of service.</p><p><strong>(c)</strong> Dental Assistants employed by DHSV or Ballarat Health Service are entitled to 91 hours and 12 minutes of paid personal leave or as provided by the NES (whichever is greater) for each year of service</p><p><strong>55.2</strong> Access to Paid Personal Leave</p><p><strong>(a)</strong> Subject to the conditions set out in this clause, an Employee may take paid personal leave if the leave is taken:</p><p><strong>(i)</strong> due to personal illness or injury (sick leave); or</p><p><strong>(ii)</strong> to care for or support a member of the Employee&#39;s immediate family or household because of: <strong>(A)</strong> a personal illness or injury affecting them; or <strong>(B)</strong> an unexpected emergency affecting them (carer&#39;s leave).</p><p><strong>(b)</strong> In normal circumstances an Employee must not take carer&#39;s leave under this clause where another person has taken leave on the same occasion to care for the same person.</p><p><strong>55.3</strong> Sick leave</p><p><strong>(a)</strong> General</p><p>An Employee may take personal leave for the reasons described at subclause 55.2 above and 55.3(b) below.</p><p><strong>(b)</strong> Personal Leave to Attend Registered Health Practitioner Appointments</p><p><strong>(i)</strong> Employees who are required to be absent from rostered ordinary shifts on account of attending a registered health practitioner for an appointment for: <strong>(A)</strong> treatment <strong>(B)</strong> rehabilitation <strong>(C)</strong> diagnosis Will be entitled to use accumulated personal/carer’s leave for the duration of the appointment and reasonable travel time where the appointment cannot be reasonably obtained at a time that doesn’t conflict with the Employee’s rostered ordinary shifts, subject to the following requirements.</p><p><strong>(ii)</strong> Employees, when seeking to utilise accumulated personal/carers leave in accordance with this clause: <strong>(A)</strong> must give reasonable notice to the Employer of their intent to take leave in accordance with this clause; <strong>(B)</strong> must receive approval from the Employer prior to the appointment; <strong>(C)</strong> must provide evidence that satisfies a reasonable purpose that the request is in accordance with this clause; <strong>(D)</strong> will endeavour to arrange the appointment, where possible, at the start or end of their rostered shift.</p><p><strong>(c)</strong> Evidence requirements</p><p><strong>(i)</strong> An Employee taking sick leave in accordance with sub- clause 55.2 will give the Employer evidence that would satisfy a reasonable person the Employee is absent due to personal illness or injury. Evidence that would satisfy a reasonable person that the Employee is absent due to personal illness or injury includes: <strong>(A)</strong> a medical certificate from a registered health practitioner; or <strong>(B)</strong> a Statutory Declaration signed by the Employee with respect to absences on three occasions in any one year not exceeding three consecutive working days each.</p><p><strong>(ii)</strong> Evidence requirements for sick leave taken in accordance with sub-clause 55.3(b) is dealt with at sub-clause 55.3(b)(ii)</p><p><strong>(d)</strong> Exception to evidence requirement – single day absences An Employee will not be entitled to this benefit if the Employee fails to notify the Employer pursuant to health service procedure of the single day absence as set out at subclause 55.3(e) below.</p><p><strong>(i)</strong> An Employee other than those listed at subclauses 55.3(d)(ii)-(iii): <strong>(A)</strong> may be absent through personal illness or injury for one day without furnishing evidence on not more than three (3) occasions in any one year of service; and, <strong>(B)</strong> where the Employees do not utilise the single day absences referred to in subclause 55.3(d)(i)((A)) for a period of five years, an additional 5 days’ personal/carer’s leave will be added to the Employee’s accrued entitlement.</p><p><strong>(ii)</strong> Dental Assistants employed by DHSV or Ballarat Health Service may be absent through personal illness or injury for one day without furnishing evidence on not more than five (5) occasions in any one year of service</p><p><strong>(iii)</strong> Managers &amp; Administrative Workers employed by the Royal Women’s Hospital or Royal Children’s Hospital may be absent through personal illness or injury on six (6) days in any one year of service (as either single days or as two days at a time) without having to provide evidence to the Employer.</p><p><strong>(e)</strong> Notice requirements</p><p><strong>(i)</strong> An Employee should inform the Employer of their absence no less than 1.5 hours prior to the commencement of the rostered shift or as soon as reasonably practicable to allow the Employer to take necessary steps to assess the impact the absence has on service delivery, patient care and workload.</p><p><strong>(ii)</strong> The notice must advise the Employer of the period, or expected period, of the leave.</p><p><strong>(iii)</strong> The Employer will inform Employees of the procedure for notification by Employees of their inability to attend work due to illness or injury. All such notifications will be registered, detailing the time and name of the Employee.</p><p><strong>55.4</strong> Carer’s leave</p><p><strong>(a)</strong> Evidence requirements</p><p><strong>(i)</strong> The Employee must, if required by the Employer, establish by production of a statutory declaration or other evidence that would satisfy a reasonable person, that a member of the Employee&#39;s immediate family or household has either: <strong>(A)</strong> an illness or injury; or <strong>(B)</strong> an unexpected emergency,</p><p><strong>(ii)</strong> that requires their care or support. In the case of an unexpected emergency, the Employee will identify the nature of the emergency. An &#39;unexpected emergency&#39; includes providing care or support to a member experiencing family violence.</p><p><strong>(b)</strong> Notice requirements</p><p><strong>(i)</strong> The Employee must, where practicable, give the Employer notice of the intention to take leave prior to the absence, that includes: <strong>(A)</strong> the name of the person requiring care or support and their relationship to the Employee; <strong>(B)</strong> the reasons for taking such leave; and <strong>(C)</strong> the estimated length of absence.</p><p><strong>(ii)</strong> If it is not practicable for the Employee to give prior notice of absence, the Employee must notify the Employer of the absence by telephone at the first opportunity on the day of absence.</p><p><strong>(c)</strong> Unpaid leave where accruals exhausted</p><p><strong>(i)</strong> Where an Employee has exhausted all paid personal/carer’s leave entitlements, the Employee is entitled to take unpaid carer’s leave to provide care and support in the circumstances outlined in subclause 55.4(a) and where they continue to meet the notice requirements at subclause 55.4(b).</p><p><strong>(ii)</strong> The Employer and the Employee will agree on the period. In the absence of agreement the Employee is entitled to take up to two (2) days&#39; unpaid carer’s leave per occasion.</p><p><strong>55.5</strong> Personal Leave on a Public Holiday See also <a href="/eba/ebas/has-managers-admin/common-terms/leave/69-public-holidays.html">clause 69</a> (Public Holidays)</p><p><strong>(a)</strong> If the period during which an Employee takes paid personal leave includes a day or part day that is a public holiday in the place where the Employee is based for work purposes, the Employee is taken not to be on paid personal leave on that public holiday.</p><p><strong>55.6</strong> Portability of Personal Leave</p><p><strong>(a)</strong> Where an Employee terminates their employment at a:</p><p><strong>(i)</strong> Employer covered by this Agreement or;</p><p><strong>(ii)</strong> a community health centre registered pursuant to the Health Services Act 1988 (or the former Hospitals and Charities Act 1958) and commences employment with an Employer covered by this Agreement within the allowable period of absence, accumulated personal leave up to a maximum of 1,976 hours at the date of such termination will be credited to the Employee at their new employment as accumulated personal leave.</p><p><strong>(b)</strong> An Employee must produce a written statement from their previous employer specifying the amount of accumulated personal leave at the time of termination, as soon as reasonably practicable following termination, however, an Employer cannot rely on an Employee’s delay in providing a written statement in refusing to grant portability of Personal Leave in accordance with this clause.</p><p><strong>(c)</strong> Where an Employee remains engaged on casual bank/or as a casual Employee with their previous employer, the Employee must provide evidence that their previous employer has removed any and all personal leave accrual prior to the new employer providing a benefit under this clause.</p><p><strong>(d)</strong> Provided further that where any Employee for the sole purpose of undertaking a course of study related to their employment, is, with the written approval of the Employer, absent without pay for up to but not exceeding 52 weeks, such absence will not be deemed to have broken continuity of service but will not be counted as service for the purpose of establishing entitlement to personal leave portability.</p><p><strong>(e)</strong> For the purpose of this subclause, the allowable period of absence means in respect of any period of absence from employment between engagement with one Employer and another or re- engagement with the same Employer that does not exceed five weeks in addition to the total period of annual leave, long service leave and or personal leave which the Employee actually receives on termination or for which he or she is paid in lieu.</p><p><strong>55.7</strong> Personal Leave and additional shifts above ordinary hours</p><p><strong>(a)</strong> No payment of personal leave will be made to an Employee where the shift or hours not worked due to illness or injury are in addition to an Employee’s ordinary hours of work.</p><p><strong>(b)</strong> For the avoidance of doubt, this provision operates in relation to additional shifts or hours an Employee has been requested to work above their ordinary hours but subsequently cannot work those hours due to illness or injury.</p><p><strong>55.8</strong> Casual Employment – Caring Responsibilities</p><p><strong>(a)</strong> Subject to the evidentiary and notice requirements that apply to Carer&#39;s Leave under clause 55.4, a casual Employee is entitled to be unavailable to attend work, or to leave work, if they need to provide care or support to a member of the Employee&#39;s immediate family or household because of:</p><p><strong>(i)</strong> a personal illness, or personal injury, affecting them; or</p><p><strong>(ii)</strong> an unexpected emergency affecting them; or</p><p><strong>(iii)</strong> the birth of a child.</p><p><strong>(b)</strong> The Employer and the Employee will agree on the period for which the Employee will be entitled to be unavailable to attend work. In the absence of agreement, the Employee is entitled to not be available to attend work for up to two days per occasion, which may be taken as a single continuous period of up to two days or any separate periods to which the Employer and Employer agree.</p><p><strong>(c)</strong> The casual Employee is not entitled to any payment for the period of non-attendance.</p><p><strong>(d)</strong> An Employer must not fail to re-engage a casual Employee because the Employee accessed the entitlements provided for in this clause. The rights of an Employer to engage or not to engage a casual Employee are otherwise not affected.</p><p><strong>55.9</strong> Planned Personal Leave</p><p><strong>(a)</strong> Where an Employee seeks to use accumulated personal/carer’s leave for the purpose of a planned medical procedure, the Employee must give notice to the Employer as soon as reasonably practicable to allow the Employer to take necessary steps to assess the impact the absence has on service delivery, patient care and workload.</p><p><strong>(b)</strong> In addition, the Employer may request of the Employee additional information from the Employee’s treating medical practitioner for the purpose of assisting the Employee in returning to their substantive duties and hours of work, including:</p><p><strong>(i)</strong> the date of the medical procedure</p><p><strong>(ii)</strong> the anticipated period of time that the Employee will be unfit for duty</p><p><strong>(iii)</strong> any reasonable adjustments that the Employer can make to assist in the Employee’s return to their substantive duties and hours of work.</p><p>Plain language terms: sick leave, sick day, carer&#39;s leave, off sick, unwell.</p>',69)])])}const u=t(n,[["render",s]]);export{m as __pageData,u as default};
